package main

import (
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"io"
	"mime/multipart"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const (
	maxUploadSize = 10 << 20 // 10 MB
	uploadDir     = "./public/uploads"
)

var allowedExtensions = map[string]bool{
	".jpg":  true,
	".jpeg": true,
	".png":  true,
	".gif":  true,
	".webp": true,
	".pdf":  true,
	".doc":  true,
	".docx": true,
	".xls":  true,
	".xlsx": true,
	".txt":  true,
	".zip":  true,
	".tar":  true,
	".gz":   true,
	".rar":  true,
}

var allowedMimeTypes = map[string]bool{
	"image/jpeg":      true,
	"image/png":       true,
	"image/gif":       true,
	"image/webp":      true,
	"application/pdf": true,
	"application/msword": true,
	"application/vnd.openxmlformats-officedocument.wordprocessingml.document":   true,
	"application/vnd.ms-excel":                                                  true,
	"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet":         true,
	"text/plain":      true,
	"application/zip": true,
	"application/x-tar": true,
	"application/gzip":  true,
	"application/x-rar-compressed": true,
	"application/x-zip-compressed": true,
}

func init() {
	if err := os.MkdirAll(uploadDir, 0755); err != nil {
		panic(fmt.Sprintf("Failed to create upload directory: %v", err))
	}
}

func generateSecureFilename(originalFilename string) (string, error) {
	ext := strings.ToLower(filepath.Ext(originalFilename))
	
	randomBytes := make([]byte, 16)
	if _, err := rand.Read(randomBytes); err != nil {
		return "", err
	}
	
	randomName := hex.EncodeToString(randomBytes)
	return randomName + ext, nil
}

func validateFile(header *multipart.FileHeader) error {
	ext := strings.ToLower(filepath.Ext(header.Filename))
	
	if !allowedExtensions[ext] {
		return fmt.Errorf("file extension %s is not allowed", ext)
	}
	
	contentType := header.Header.Get("Content-Type")
	if !allowedMimeTypes[contentType] {
		return fmt.Errorf("content type %s is not allowed", contentType)
	}
	
	if header.Size > maxUploadSize {
		return fmt.Errorf("file size exceeds maximum allowed size of %d bytes", maxUploadSize)
	}
	
	if header.Size == 0 {
		return fmt.Errorf("file is empty")
	}
	
	return nil
}

func sanitizeFilename(filename string) string {
	filename = filepath.Base(filename)
	
	invalidChars := []string{"..", "/", "\\", "\x00"}
	for _, char := range invalidChars {
		filename = strings.ReplaceAll(filename, char, "")
	}
	
	return filename
}

func FileUploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}
	
	r.Body = http.MaxBytesReader(w, r.Body, maxUploadSize+1024)
	
	if err := r.ParseMultipartForm(maxUploadSize); err != nil {
		http.Error(w, "File too large or invalid form data", http.StatusBadRequest)
		return
	}
	
	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Error retrieving file from form", http.StatusBadRequest)
		return
	}
	defer file.Close()
	
	header.Filename = sanitizeFilename(header.Filename)
	
	if err := validateFile(header); err != nil {
		http.Error(w, fmt.Sprintf("File validation failed: %v", err), http.StatusBadRequest)
		return
	}
	
	secureFilename, err := generateSecureFilename(header.Filename)
	if err != nil {
		http.Error(w, "Error generating secure filename", http.StatusInternalServerError)
		return
	}
	
	filePath := filepath.Join(uploadDir, secureFilename)
	
	dst, err := os.OpenFile(filePath, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0644)
	if err != nil {
		http.Error(w, "Error creating file on server", http.StatusInternalServerError)
		return
	}
	defer dst.Close()
	
	written, err := io.Copy(dst, file)
	if err != nil {
		os.Remove(filePath)
		http.Error(w, "Error saving file", http.StatusInternalServerError)
		return
	}
	
	if written != header.Size {
		os.Remove(filePath)
		http.Error(w, "File size mismatch", http.StatusInternalServerError)
		return
	}
	
	relativePath := filepath.Join("/uploads", secureFilename)
	
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, `{"success": true, "path": "%s", "filename": "%s", "size": %d}`, 
		relativePath, secureFilename, header.Size)
}

func main() {
	http.HandleFunc("/upload", FileUploadHandler)
	
	fs := http.FileServer(http.Dir("./public"))
	http.Handle("/uploads/", http.StripPrefix("/uploads/", http.FileServer(http.Dir(uploadDir))))
	http.Handle("/", fs)
	
	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}